import React, { useState, useMemo, useRef, useCallback, useDeferredValue, useTransition } from 'react';
import {
    Box,
    Table,
    TableBody,
    TableCell,
    TableContainer,
    TableHead,
    TableRow,
    Paper,
    Button,
    Typography,
    FormControl,
    Select,
    MenuItem,
    InputLabel,
    SelectChangeEvent,
    Alert,
    IconButton,
    Tooltip,
    Divider,
    TextField,
    InputAdornment,
    Dialog,
    DialogTitle,
    DialogContent,
    DialogActions
} from '@mui/material';
import { calculateDonationTotal } from '@/utils/eventCalculations';
import { AttendeeServices } from '@/api';
import { AttendeeBasicInfo } from '@/types/attendee.types';
import { getEventId } from '@/constants/ApiConstants';
import { useAttendeesStore, useLoadingStore } from '@/store';
import { ApiGlobalStateManager } from '@/lib/api-state';
import { CallStatus } from '@/types/api.types';
import { getSelectedEventContext } from '@/utils/eventContext';
import { EventActionDialog } from '@/components/EventActionDialog';
import CheckCircleIcon from '@mui/icons-material/CheckCircle';
import CancelIcon from '@mui/icons-material/Cancel';
import PhoneIcon from '@mui/icons-material/Phone';
import RestaurantIcon from '@mui/icons-material/Restaurant';
import SchoolIcon from '@mui/icons-material/School';
import CurrencyRupeeIcon from '@mui/icons-material/CurrencyRupee';
import GroupIcon from '@mui/icons-material/Group';
import EventAvailableIcon from '@mui/icons-material/EventAvailable';
import ClearIcon from '@mui/icons-material/Clear';
import { foodColors, foodColorList, foodColorFallbackList } from '@/constants/ThemeConstants';
import { UnixDateTimeToReadable } from '@/utils/common';
import { logger } from '@/utils/logger';
import { AttendeeRow } from './AttendeeRow';

export const Attendee: React.FC = () => {
    const eventId = getEventId();
    const { attendeeListState, setAttendeeListState } = useAttendeesStore();
    const { setLoading } = useLoadingStore();
    const tableRef = useRef<HTMLDivElement>(null);
    const hasFetchedRef = useRef<boolean>(false);
    
    // Get event context to check if checkin is enabled
    const [isCheckinEnabled, setIsCheckinEnabled] = React.useState<boolean>(true);
    const [selectedEvent, setSelectedEvent] = React.useState<any>(null);
    
    React.useEffect(() => {
        const eventContext = getSelectedEventContext();
        if (eventContext) {
            setIsCheckinEnabled(eventContext.isCheckinEnabled ?? true);
            setSelectedEvent(eventContext);
            logger.debug('Attendee', 'Event checkin enabled', eventContext.isCheckinEnabled);
        }
    }, []);
    
    // State for messages
    const [checkInMessage, setCheckInMessage] = useState<{ type: 'success' | 'error', text: string } | null>(null);
    const [cancelMessage, setCancelMessage] = useState<{ type: 'success' | 'error', text: string } | null>(null);
    const [updateMessage, setUpdateMessage] = useState<{ type: 'success' | 'error', text: string } | null>(null);

    // Filter states
    const [batchFilter, setBatchFilter] = useState<string>('all');
    const [checkinFilter, setCheckinFilter] = useState<string>('all');
    const [attendingFilter, setAttendingFilter] = useState<string>('attending-true');
    const [foodFilter, setFoodFilter] = useState<string>('all');
    const [schoolFilter, setSchoolFilter] = useState<string>('all');
    const [searchFilter, setSearchFilter] = useState<string>('');
    const [displayCount, setDisplayCount] = useState<number>(50);

    // useTransition keeps the input/UI responsive while the heavy filter recompute happens
    const [, startFilterTransition] = useTransition();

    // Ref to store timeout for debouncing
    const searchTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

    // Whenever any filter changes, reset back to the first 50 rows so we don't carry
    // a previously-expanded "Show All" view through new filter sets (which causes
    // the page to render thousands of rows on each keystroke).
    const setFilterAndResetDisplay = useCallback(<T,>(setter: React.Dispatch<React.SetStateAction<T>>) => {
        return (value: T) => {
            startFilterTransition(() => {
                setter(value);
                setDisplayCount(50);
            });
        };
    }, []);

    // Handler for search input change with debouncing
    const handleSearchChange = useCallback((value: string) => {
        if (searchTimeoutRef.current) {
            clearTimeout(searchTimeoutRef.current);
        }
        searchTimeoutRef.current = setTimeout(() => {
            startFilterTransition(() => {
                setSearchFilter(value);
                setDisplayCount(50);
            });
        }, 300);
    }, []);

    // Deferred search filter for non-blocking search
    const deferredSearchFilter = useDeferredValue(searchFilter);
    
    // Sorting state
    const [sortBy, setSortBy] = useState<'name' | 'batch' | 'checkin' | 'registration'>('registration');
    const [sortOrder, setSortOrder] = useState<'asc' | 'desc'>('desc');

    // Dialog states
    const [checkInDialogOpen, setCheckInDialogOpen] = useState(false);
    const [cancelDialogOpen, setCancelDialogOpen] = useState(false);
    const [updateDialogOpen, setUpdateDialogOpen] = useState(false);
    const [selectedAttendee, setSelectedAttendee] = useState<AttendeeBasicInfo | null>(null);

    // Donation dialog state
    const [donationDialogOpen, setDonationDialogOpen] = useState(false);
    const [donationAmount, setDonationAmount] = useState<string>('');
    const [donationTxnRef, setDonationTxnRef] = useState<string>('');
    const [isCheckInSubmitting, setIsCheckInSubmitting] = useState(false);
    const [isCancelSubmitting, setIsCancelSubmitting] = useState(false);
    const [isUpdateSubmitting, setIsUpdateSubmitting] = useState(false);
    const [isDonationSubmitting, setIsDonationSubmitting] = useState(false);

    // Info dialog state
    const [infoDialogState, setInfoDialogState] = useState<{
        open: boolean;
        attendee: AttendeeBasicInfo | null;
    }>({
        open: false,
        attendee: null
    });

    // Deferred values for non-blocking updates
    const deferredInfoAttendee = useDeferredValue(infoDialogState.attendee);
    const deferredSelectedAttendee = useDeferredValue(selectedAttendee);

    // Memoized donation totals - recalculates only when donation data changes (async/non-blocking)
    const infoDonationTotal = useMemo(
        () => calculateDonationTotal(deferredInfoAttendee?.donation),
        [deferredInfoAttendee?.donation]
    );

    const selectedAttendeeDonationTotal = useMemo(
        () => calculateDonationTotal(deferredSelectedAttendee?.donation),
        [deferredSelectedAttendee?.donation]
    );

    // Get food options from selected event
    const foodOptions = useMemo(() => {
        if (selectedEvent?.food && selectedEvent?.isFoodEnabled) {
            return selectedEvent.food.split(',').map((opt: string) => opt.trim()).filter((opt: string) => opt.length > 0);
        }
        return [];
    }, [selectedEvent?.food, selectedEvent?.isFoodEnabled]);

    // Food preference color mapping - generate distinct light shades dynamically based on actual attendee data
    // Memoize food color palette calculation
    const foodColorPalette = useMemo(() => {
        const paletteColors = foodColorList;

        const colorMap: { [key: string]: { bg: string; text: string } } = {
            'null': foodColors.grey
        };

        // Get unique food preferences from actual attendee data
        if (Array.isArray(attendeeListState.data)) {
            const uniqueFoodPrefs = Array.from(
                new Set(
                    attendeeListState.data
                        .map((a: AttendeeBasicInfo) => (a.foodPreference || 'Null').trim())
                        .filter((f: string) => f !== '' && f.toLowerCase() !== 'null')
                )
            );

            // Assign colors to actual food preferences
            uniqueFoodPrefs.forEach((food: string, index: number) => {
                colorMap[food.toLowerCase()] = paletteColors[index % paletteColors.length];
            });
        }

        return colorMap;
    }, [attendeeListState.data]);

    const getFoodColor = useCallback((foodPref: string): { bg: string; text: string } => {
        const normalizedFood = (foodPref || 'Null').toLowerCase().trim();
        
        // Rule-based color assignment
        // If contains "veg" (but not "non-veg" or "nonveg") -> green shades
        if (normalizedFood.includes('veg') && !normalizedFood.includes('non-veg') && !normalizedFood.includes('nonveg') && !normalizedFood.includes('non veg')) {
            return foodColors.green;
        }
        
        // If contains "non-veg" or "nonveg" -> red shades
        if (normalizedFood.includes('non-veg') || normalizedFood.includes('nonveg') || normalizedFood.includes('non veg')) {
            return foodColors.red;
        }

        // Try to find exact match in palette (for other foods)
        if (foodColorPalette[normalizedFood]) {
            return foodColorPalette[normalizedFood];
        }

        // Try to find partial match in palette
        for (const [key, colors] of Object.entries(foodColorPalette)) {
            if (key !== 'null' && (normalizedFood.includes(key) || key.includes(normalizedFood))) {
                return colors;
            }
        }

        // Default for null
        if (normalizedFood === 'null' || normalizedFood === '') {
            return foodColorPalette['null'];
        }

        // Random color for other foods (generate based on hash of food name for consistency)
        const hashCode = normalizedFood.split('').reduce((acc, char) => {
            return char.charCodeAt(0) + ((acc << 5) - acc);
        }, 0);
        
        return foodColorFallbackList[Math.abs(hashCode) % foodColorFallbackList.length];
    }, [foodColorPalette]);

    // Load attendee list
    React.useEffect(() => {
        if (
            eventId && 
            !hasFetchedRef.current &&
            attendeeListState.status !== CallStatus.Success && 
            attendeeListState.status !== CallStatus.InProgress
        ) {
            hasFetchedRef.current = true;
            ApiGlobalStateManager(AttendeeServices.GetAttendees(eventId), setAttendeeListState);
        }
    }, [eventId, attendeeListState.status]);

    // Get unique batches for filter
    const uniqueBatches = useMemo(() => {
        if (!Array.isArray(attendeeListState.data)) return [];
        const batches = new Set(attendeeListState.data.map((a: AttendeeBasicInfo) => a.profile?.batch).filter((b): b is number => b != null));
        return Array.from(batches).sort((a, b) => a - b);
    }, [attendeeListState.data]);

    // Get unique food preferences for filter
    const uniqueFoodPreferences = useMemo(() => {
        if (!Array.isArray(attendeeListState.data)) return [];
        const foods = new Set(
            attendeeListState.data.map((a: AttendeeBasicInfo) => (a.foodPreference || 'Null').trim())
        );
        return Array.from(foods).sort();
    }, [attendeeListState.data]);

    // Get unique schools for filter
    const uniqueSchools = useMemo(() => {
        if (!Array.isArray(attendeeListState.data)) return [];
        const schools = new Set(
            attendeeListState.data
                .map((a: AttendeeBasicInfo) => a.profile?.firstJnvName)
                .filter((school): school is string => school != null && school.trim() !== '')
        );
        return Array.from(schools).sort();
    }, [attendeeListState.data]);

    // Filter attendees - optimized with early exits
    const filteredAttendees = useMemo(() => {
        if (!Array.isArray(attendeeListState.data) || attendeeListState.data.length === 0) {
            return [];
        }

        let filtered = [...attendeeListState.data];
        const searchLower = deferredSearchFilter.toLowerCase().trim();

        // Apply all filters in a single pass when possible
        filtered = filtered.filter((a: AttendeeBasicInfo) => {
            // Search filter
            if (searchLower !== '') {
                const nameMatch = a.profile?.name?.toLowerCase().includes(searchLower);
                const batchMatch = a.profile?.batch?.toString().includes(searchLower);
                const phoneMatch = a.profile?.phone?.toLowerCase().includes(searchLower);
                const foodMatch = a.foodPreference && a.foodPreference.toLowerCase().includes(searchLower);
                
                if (!nameMatch && !batchMatch && !phoneMatch && !foodMatch) {
                    return false;
                }
            }

            // Batch filter
            if (batchFilter !== 'all' && a.profile?.batch !== parseInt(batchFilter)) {
                return false;
            }

            // School filter
            if (schoolFilter !== 'all' && a.profile?.firstJnvName !== schoolFilter) {
                return false;
            }

            // Check-in filter
            if (checkinFilter === 'checked-in') {
                if (!a.checkedInAt || a.checkedInAt === 0) return false;
            } else if (checkinFilter === 'not-checked-in') {
                if (a.checkedInAt && a.checkedInAt > 0) return false;
            }

            // Attending filter based on headcount
            if (attendingFilter === 'attending-true') {
                if ((a.headCount ?? 1) <= 0) return false;
            } else if (attendingFilter === 'attending-false') {
                if ((a.headCount ?? 1) > 0) return false;
            }

            // Food preference filter
            if (foodFilter !== 'all') {
                const attendeeFood = (a.foodPreference || 'Null').trim().toLowerCase();
                if (attendeeFood !== foodFilter.toLowerCase()) {
                    return false;
                }
            }

            return true;
        });

        // Sort - using stable sort algorithm
        if (sortBy === 'name') {
            filtered.sort((a, b) => (a.profile?.name ?? '').localeCompare(b.profile?.name ?? ''));
        } else if (sortBy === 'batch') {
            filtered.sort((a, b) => (a.profile?.batch ?? 0) - (b.profile?.batch ?? 0));
        } else if (sortBy === 'checkin') {
            filtered.sort((a, b) => (a.checkedInAt || 0) - (b.checkedInAt || 0));
        } else if (sortBy === 'registration') {
            filtered.sort((a, b) => (a.createdAt || 0) - (b.createdAt || 0));
        }

        // Apply sort order
        if (sortOrder === 'desc') {
            filtered.reverse();
        }

        return filtered;
    }, [attendeeListState.data, batchFilter, checkinFilter, attendingFilter, foodFilter, schoolFilter, deferredSearchFilter, sortBy, sortOrder]);

    const handleSortClick = useCallback((column: 'name' | 'batch' | 'checkin' | 'registration') => {
        if (sortBy === column) {
            // Toggle sort order if clicking the same column
            setSortOrder(sortOrder === 'asc' ? 'desc' : 'asc');
        } else {
            // Set new column and default to ascending
            setSortBy(column);
            setSortOrder('asc');
        }
    }, [sortBy, sortOrder]);

    const handleCheckIn = useCallback(async (userId: string, foodPreference: string = "", count: number = 1) => {
        if (!eventId) return;

        setLoading(true, 'Checking in...');
        try {
            // Update food/headcount first, then check in
            await AttendeeServices.UpdateRegistrationById(eventId, userId, foodPreference, count);
            const response = await AttendeeServices.CheckInAttendee(eventId, userId, true);

            if (response.data.status >= 200 && response.data.status < 300) {
                setCheckInMessage({ type: 'success', text: 'Check-in successful!' });

                // Refresh the attendee list from the server to get accurate timestamp
                const refreshResponse = await AttendeeServices.GetAttendees(eventId);
                if (refreshResponse.data.status >= 200 && refreshResponse.data.status < 300) {
                    setAttendeeListState({
                        status: CallStatus.Success,
                        data: refreshResponse.data.result || [],
                        httpStatus: refreshResponse.data.status,
                        timestamp: new Date(),
                    });
                }

                // Clear success message after 3 seconds
                setTimeout(() => {
                    setCheckInMessage(null);
                }, 3000);
            } else {
                setCheckInMessage({ type: 'error', text: 'Check-in failed' });
            }
        } catch (error) {
            setCheckInMessage({ type: 'error', text: error instanceof Error ? error.message : 'An error occurred' });
        } finally {
            setLoading(false);
        }
        // NOTE: deliberately exclude `attendeeListState` from deps — its identity
        // changes on every store update and would invalidate every memoized row.
        // We always read the latest list directly from the API refresh response.
    }, [eventId, setLoading, setAttendeeListState]);

    const handleCancelRegistration = useCallback(async (userId: string) => {
        if (!eventId) return;

        setLoading(true, 'Cancelling registration...');
        try {
            const response = await AttendeeServices.DeleteRegistrationById(
                eventId,
                userId
            );

            if (response.data.status >= 200 && response.data.status < 300) {
                setCancelMessage({ type: 'success', text: 'Registration cancelled successfully!' });

                // Update only the affected attendee using the latest store state
                // (functional update keeps this callback stable across renders).
                const current = useAttendeesStore.getState().attendeeListState;
                const currentData = Array.isArray(current.data) ? current.data : [];
                const updatedData = currentData.map((a: AttendeeBasicInfo) =>
                    a.userId === userId ? { ...a, headCount: 0, foodPreference: '' } : a
                );
                setAttendeeListState({ ...current, data: updatedData });

                setTimeout(() => {
                    setCancelMessage(null);
                }, 3000);
            } else {
                setCancelMessage({ type: 'error', text: 'Cancel registration failed' });
            }
        } catch (error) {
            setCancelMessage({ type: 'error', text: error instanceof Error ? error.message : 'An error occurred' });
        } finally {
            setLoading(false);
        }
    }, [eventId, setLoading, setAttendeeListState]);

    const handleCheckInClick = useCallback((attendee: AttendeeBasicInfo) => {
        setSelectedAttendee(attendee);
        setCheckInDialogOpen(true);
    }, []);

    const handleCancelClick = useCallback((attendee: AttendeeBasicInfo) => {
        setSelectedAttendee(attendee);
        setCancelDialogOpen(true);
    }, []);

    const handleCheckInConfirm = useCallback(async (foodPreference: string, count: number) => {
        if (!selectedAttendee || isCheckInSubmitting) return;

        setIsCheckInSubmitting(true);
        try {
            await handleCheckIn(selectedAttendee.userId, foodPreference, count);
        } finally {
            setIsCheckInSubmitting(false);
            setCheckInDialogOpen(false);
            setSelectedAttendee(null);
        }
    }, [selectedAttendee, handleCheckIn, isCheckInSubmitting]);

    const handleCancelConfirm = useCallback(async () => {
        if (!selectedAttendee || isCancelSubmitting) return;

        setIsCancelSubmitting(true);
        try {
            await handleCancelRegistration(selectedAttendee.userId);
        } finally {
            setIsCancelSubmitting(false);
            setCancelDialogOpen(false);
            setSelectedAttendee(null);
        }
    }, [selectedAttendee, handleCancelRegistration, isCancelSubmitting]);

    const handleDonationClick = useCallback((attendee: AttendeeBasicInfo) => {
        setSelectedAttendee(attendee);
        setDonationAmount('');
        setDonationTxnRef('');
        setDonationDialogOpen(true);
    }, []);

    const handleDonationAmountChange = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
        const sanitizedValue = e.target.value.replace(/[^0-9]/g, '');
        setDonationAmount(sanitizedValue);
    }, []);

    const handleDonationTxnRefChange = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
        setDonationTxnRef(e.target.value);
    }, []);

    const handleDonationConfirm = useCallback(async () => {
        if (!selectedAttendee || isDonationSubmitting) return;

        // Validate amount
        const amount = donationAmount.trim();
        const txnRef = donationTxnRef.trim().replace(/\s+/g, '_'); // Replace spaces with underscores

        if (!amount || !txnRef) {
            alert('Please enter both amount and transaction reference');
            return;
        }

        const amountNum = parseInt(amount);
        if (isNaN(amountNum) || amountNum <= 0) {
            alert('Please enter a valid amount');
            return;
        }

        // Create donation string in format: amount@txnRef
        const donation = `${amount}@${txnRef}`;

        setIsDonationSubmitting(true);
        try {
            const response = await AttendeeServices.AddDonation(eventId, selectedAttendee.userId, donation);

            if (response.data?.status >= 200 && response.data?.status < 300) {
                // Refresh the attendee list
                const refreshResponse = await AttendeeServices.GetAttendees(eventId);
                if (refreshResponse.data.status >= 200 && refreshResponse.data.status < 300) {
                    setAttendeeListState({
                        status: CallStatus.Success,
                        data: refreshResponse.data.result || [],
                        httpStatus: refreshResponse.data.status,
                        timestamp: new Date(),
                    });
                }

                setDonationDialogOpen(false);
                setSelectedAttendee(null);
                setDonationAmount('');
                setDonationTxnRef('');
            } else {
                alert('Failed to add donation');
            }
        } catch (error) {
            logger.error('Attendee', 'Error adding donation', error);
            alert('Error adding donation');
        } finally {
            setIsDonationSubmitting(false);
        }
    }, [selectedAttendee, donationAmount, donationTxnRef, eventId, setAttendeeListState, isDonationSubmitting]);

    const handleUpdateClick = useCallback((attendee: AttendeeBasicInfo) => {
        setSelectedAttendee(attendee);
        setUpdateDialogOpen(true);
    }, []);

    const handleUpdateConfirm = useCallback(async (foodPreference: string, count: number) => {
        if (!eventId || !selectedAttendee || isUpdateSubmitting) return;

        setIsUpdateSubmitting(true);
        setLoading(true, 'Updating registration...');
        
        try {
            const response = await AttendeeServices.UpdateRegistrationById(eventId, selectedAttendee.userId, foodPreference, count);

            if (response.data.status >= 200 && response.data.status < 300) {
                setUpdateMessage({ type: 'success', text: 'Registration updated successfully!' });

                // Refresh the attendee list from the server to get updated data
                const refreshResponse = await AttendeeServices.GetAttendees(eventId);
                if (refreshResponse.data.status >= 200 && refreshResponse.data.status < 300) {
                    setAttendeeListState({
                        status: CallStatus.Success,
                        data: refreshResponse.data.result || [],
                        httpStatus: refreshResponse.data.status,
                        timestamp: new Date(),
                    });
                }

                // Clear success message after 3 seconds
                setTimeout(() => {
                    setUpdateMessage(null);
                }, 3000);
            } else {
                setUpdateMessage({ type: 'error', text: 'Update failed' });
            }
        } catch (error) {
            setUpdateMessage({ type: 'error', text: error instanceof Error ? error.message : 'An error occurred' });
        } finally {
            setLoading(false);
            setIsUpdateSubmitting(false);
            setUpdateDialogOpen(false);
            setSelectedAttendee(null);
        }
    }, [eventId, selectedAttendee, setLoading, setAttendeeListState, isUpdateSubmitting]);
    const handleInfoClick = useCallback((attendee: AttendeeBasicInfo) => {
        setInfoDialogState({
            open: true,
            attendee: attendee
        });
    }, []);

    const handleInfoDialogClose = useCallback(() => {
        setInfoDialogState({
            open: false,
            attendee: null
        });
    }, []);

    const handleExportScreenshot = useCallback(async () => {
        try {
            const node = tableRef.current;
            if (node) {
                const eventIdStr = eventId || 'unknown';
                const selectedBatch = batchFilter === 'all' ? 'all-batches' : batchFilter;

                // Format: YYYYMMDDHHMM
                const now = new Date();
                const dateHour = `${now.getFullYear()}${String(now.getMonth() + 1).padStart(2, '0')}${String(now.getDate()).padStart(2, '0')}${String(now.getHours()).padStart(2, '0')}${String(now.getMinutes()).padStart(2, '0')}`;

                const filename = `${eventIdStr}__${selectedBatch}__${dateHour}.jpeg`;

                // Lazy-load html-to-image only when the user actually exports —
                // it's a heavy dependency and was previously inflating the page bundle.
                const { toJpeg } = await import('html-to-image');

                toJpeg(node, {
                    quality: 0.95,
                    cacheBust: true,
                    pixelRatio: 2,
                    skipFonts: true,  // Skip font processing to avoid "trim" error
                    filter: (element) => {
                        // Exclude tooltip overlays and backdrops
                        if (element.classList) {
                            return !element.classList.contains('MuiTooltip-popper') &&
                                   !element.classList.contains('MuiBackdrop-root');
                        }
                        return true;
                    }
                })
                    .then(function (dataUrl) {
                        const link = document.createElement('a') as HTMLAnchorElement;
                        link.download = filename;
                        link.href = dataUrl;
                        link.click();
                    })
                    .catch(function (error) {
                        logger.error('Attendee', 'Error generating screenshot', error);
                        // Provide more detailed error message
                        const errorMsg = error?.message || error?.toString() || 'Unknown error';
                        alert(`Failed to generate screenshot.\n\nError: ${errorMsg}\n\nTry:\n1. Scroll to see all table content\n2. Close any open tooltips\n3. Use browser's built-in screenshot (Ctrl+Shift+S)`);
                    });
            } else {
                alert('Table not found. Please try again.');
            }
        }
        catch (error) {
            logger.error('Attendee', 'Error in handleExportScreenshot', error);
            alert('Failed to generate screenshot. Please try again.');
        }
    }, [eventId, batchFilter]);

    // Show/hide global loading based on attendee list status
    React.useEffect(() => {
        if (attendeeListState.status === CallStatus.InProgress) {
            setLoading(true, 'Loading attendees...');
        } else {
            setLoading(false);
        }
        
        // Cleanup on unmount
        return () => {
            setLoading(false);
        };
    }, [attendeeListState.status, setLoading]);

    if (attendeeListState.status === CallStatus.Failure || attendeeListState.status === CallStatus.BadRequest) {
        return (
            <Box sx={{ p: 2 }}>
                <Alert severity="error">Failed to load attendees</Alert>
            </Box>
        );
    }

    // Don't show any content until data is loaded
    if (attendeeListState.status !== CallStatus.Success || !Array.isArray(attendeeListState.data)) {
        return null;
    }

    return (
        <Box sx={{ p: { xs: 1, sm: 2 } }}>
            {/* Status Messages */}
            {checkInMessage && (
                <Alert severity={checkInMessage.type} sx={{ mb: 1 }}>
                    {checkInMessage.text}
                </Alert>
            )}
            {cancelMessage && (
                <Alert severity={cancelMessage.type} sx={{ mb: 1 }}>
                    {cancelMessage.text}
                </Alert>
            )}
            {updateMessage && (
                <Alert severity={updateMessage.type} sx={{ mb: 1 }}>
                    {updateMessage.text}
                </Alert>
            )}

            {/* Filters */}
            <Box sx={{ display: 'flex', gap: 1, mb: 1, flexWrap: 'wrap', alignItems: 'flex-start' }}>
                <TextField
                    size="small"
                    label="Search"
                    placeholder="Name, Batch..."
                    defaultValue={searchFilter}
                    onChange={(e) => handleSearchChange(e.target.value)}
                    sx={{ flexGrow: 1, minWidth: 200, maxWidth: 400 }}
                    slotProps={{
                        input: {
                            endAdornment: searchFilter && (
                                <InputAdornment position="end">
                                    <IconButton
                                        size="small"
                                        onClick={(e) => {
                                            const input = e.currentTarget.closest('.MuiFormControl-root')?.querySelector('input');
                                            if (input) {
                                                input.value = '';
                                                handleSearchChange('');
                                            }
                                        }}
                                        edge="end"
                                        aria-label="clear search"
                                    >
                                        <ClearIcon fontSize="small" />
                                    </IconButton>
                                </InputAdornment>
                            ),
                        },
                    }}
                />
                
                <FormControl size="small" sx={{ minWidth: 90 }}>
                    <InputLabel>Attending</InputLabel>
                    <Select
                        value={attendingFilter}
                        label="Attending"
                        onChange={(e: SelectChangeEvent) => setFilterAndResetDisplay(setAttendingFilter)(e.target.value)}
                    >
                        <MenuItem value="all">All</MenuItem>
                        <MenuItem value="attending-true">True</MenuItem>
                        <MenuItem value="attending-false">False</MenuItem>
                    </Select>
                </FormControl>

                <FormControl size="small" sx={{ minWidth: 90 }}>
                    <InputLabel>Batch</InputLabel>
                    <Select
                        value={batchFilter}
                        label="Batch"
                        onChange={(e: SelectChangeEvent) => setFilterAndResetDisplay(setBatchFilter)(e.target.value)}
                    >
                        <MenuItem value="all">All</MenuItem>
                        {uniqueBatches.map((batch: any) => (
                            <MenuItem key={batch} value={batch.toString()}>
                                {batch}
                            </MenuItem>
                        ))}
                    </Select>
                </FormControl>

                <FormControl size="small" sx={{ minWidth: 90 }}>
                    <InputLabel>Checked-In</InputLabel>
                    <Select
                        value={checkinFilter}
                        label="Checked-In"
                        onChange={(e: SelectChangeEvent) => setFilterAndResetDisplay(setCheckinFilter)(e.target.value)}
                    >
                        <MenuItem value="all">All</MenuItem>
                        <MenuItem value="checked-in">True</MenuItem>
                        <MenuItem value="not-checked-in">False</MenuItem>
                    </Select>
                </FormControl>

                <FormControl size="small" sx={{ minWidth: 105 }}>
                    <InputLabel>Food</InputLabel>
                    <Select
                        value={foodFilter}
                        label="Food"
                        onChange={(e: SelectChangeEvent) => setFilterAndResetDisplay(setFoodFilter)(e.target.value)}
                    >
                        <MenuItem value="all">All</MenuItem>
                        {uniqueFoodPreferences.map((food: string) => (
                            <MenuItem key={food} value={food}>
                                {food}
                            </MenuItem>
                        ))}
                    </Select>
                </FormControl>

                <FormControl size="small" sx={{ minWidth: 120 }}>
                    <InputLabel>School</InputLabel>
                    <Select
                        value={schoolFilter}
                        label="School"
                        onChange={(e: SelectChangeEvent) => setFilterAndResetDisplay(setSchoolFilter)(e.target.value)}
                    >
                        <MenuItem value="all">All</MenuItem>
                        {uniqueSchools.map((school: string) => (
                            <MenuItem key={school} value={school}>
                                {school}
                            </MenuItem>
                        ))}
                    </Select>
                </FormControl>

                {/* Count and download moved to table header */}
            </Box>

            {/* Attendee Table */}
            <TableContainer component={Paper} ref={tableRef}>
                <Table>
                    <TableHead sx={{ backgroundColor: 'action.hover' }}>
                        <TableRow>
                            <TableCell>
                                <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                                    <Typography 
                                        variant="subtitle2" 
                                        onClick={() => handleSortClick('name')}
                                        sx={{ fontWeight: 'bold', cursor: 'pointer', userSelect: 'none' }}
                                    >
                                        Name {sortBy === 'name' && (sortOrder === 'asc' ? '↑' : '↓')}
                                    </Typography>
                                    <Typography variant="subtitle2" sx={{ fontWeight: "bold" }}>
                                        |
                                    </Typography>
                                    <Typography 
                                        variant="subtitle2" 
                                        onClick={() => handleSortClick('batch')}
                                        sx={{ fontWeight: 'bold', cursor: 'pointer', userSelect: 'none' }}
                                    >
                                        Batch {sortBy === 'batch' && (sortOrder === 'asc' ? '↑' : '↓')}
                                    </Typography>
                                    <Typography variant="subtitle2" sx={{ fontWeight: "bold" }}>
                                        |
                                    </Typography>
                                    <Tooltip title="Sort by Registration Time">
                                        <EventAvailableIcon 
                                            onClick={() => handleSortClick('registration')}
                                            sx={{ 
                                                fontSize: '1.2rem',
                                                cursor: 'pointer',
                                                color: sortBy === 'registration' ? 'primary.main' : 'text.secondary',
                                                ml: 0.5
                                            }}
                                        />
                                    </Tooltip>
                                    {sortBy === 'registration' && (
                                        <Typography variant="subtitle2" sx={{ fontWeight: "bold" }}>
                                            {sortOrder === 'asc' ? '↑' : '↓'}
                                        </Typography>
                                    )}
                                    <Typography variant="subtitle2" sx={{ fontWeight: "bold" }}>
                                        |
                                    </Typography>
                                    <Tooltip title="Sort by Check-in Time">
                                        <CheckCircleIcon 
                                            onClick={() => handleSortClick('checkin')}
                                            sx={{ 
                                                fontSize: '1.2rem',
                                                cursor: 'pointer',
                                                color: sortBy === 'checkin' ? 'primary.main' : 'text.secondary',
                                                ml: 0.5
                                            }}
                                        />
                                    </Tooltip>
                                    {sortBy === 'checkin' && (
                                        <Typography variant="subtitle2" sx={{ fontWeight: "bold" }}>
                                            {sortOrder === 'asc' ? '↑' : '↓'}
                                        </Typography>
                                    )}
                                </Box>
                            </TableCell>
                            <TableCell align="right">
                                <Box sx={{ display: 'flex', alignItems: 'center', gap: 0, justifyContent: 'flex-end' }}>
                                    <Tooltip title="Export as Screenshot">
                                        <Button 
                                            size="small" 
                                            onClick={handleExportScreenshot}
                                            variant="contained"
                                            color="primary"
                                            disabled={filteredAttendees.length === 0}
                                            sx={{ 
                                                padding: '1px 4px 1px 4px',
                                                fontSize: '0.8125rem',
                                                minWidth: 'auto',
                                                marginLeft: 0,
                                                color: 'primary.contrastText'
                                            }}
                                        >
                                            {filteredAttendees.length}/{Array.isArray(attendeeListState.data) ? attendeeListState.data.length : 0}
                                        </Button>
                                    </Tooltip>
                                </Box>
                            </TableCell>
                        </TableRow>
                    </TableHead>
                    <TableBody>
                        {filteredAttendees.length === 0 ? (
                            <TableRow>
                                <TableCell colSpan={2} align="center">
                                    <Typography variant="body2" color="text.secondary" sx={{ py: 4 }}>
                                        No attendees found
                                    </Typography>
                                </TableCell>
                            </TableRow>
                        ) : (
                            filteredAttendees.slice(0, displayCount).map((attendee: AttendeeBasicInfo) => (
                                <AttendeeRow
                                    key={attendee.userId}
                                    attendee={attendee}
                                    isCheckinEnabled={isCheckinEnabled}
                                    getFoodColor={getFoodColor}
                                    onInfo={handleInfoClick}
                                    onDonation={handleDonationClick}
                                    onCancel={handleCancelClick}
                                    onCheckIn={handleCheckInClick}
                                    onUpdate={handleUpdateClick}
                                />
                            ))
                        )}
                    </TableBody>
                </Table>
                {/* Spacer for screenshot coverage - matches page background */}
                <Box sx={{ height: '24px', backgroundColor: 'background.default' }} />
            </TableContainer>

            {/* View All */}
            {filteredAttendees.length > displayCount && (
                <Box sx={{ display: 'flex', justifyContent: 'center', py: 2 }}>
                    <Button variant="contained" size="small" onClick={() => setDisplayCount(filteredAttendees.length)}>
                        View All ({filteredAttendees.length - displayCount} more)
                    </Button>
                </Box>
            )}

            {/* Check-in Dialog */}
            <EventActionDialog
                open={checkInDialogOpen}
                actionType="checkin"
                userName={selectedAttendee?.profile?.name || ''}
                eventTitle={selectedEvent?.title || ''}
                onClose={() => {
                    setCheckInDialogOpen(false);
                    setSelectedAttendee(null);
                }}
                onConfirm={handleCheckInConfirm}
                isFoodEnabled={!!selectedEvent?.food}
                isAccompanyEnabled={selectedEvent?.isAccompanyEnabled || false}
                foodOptions={foodOptions}
                initialFoodPreference={selectedAttendee?.foodPreference || ''}
                initialCount={selectedAttendee?.headCount ?? 1}
                isLoading={isCheckInSubmitting}
            />

            {/* Cancel Registration Dialog */}
            <EventActionDialog
                open={cancelDialogOpen}
                actionType="cancel"
                userName={selectedAttendee?.profile?.name || ''}
                eventTitle={selectedEvent?.title || ''}
                onClose={() => {
                    setCancelDialogOpen(false);
                    setSelectedAttendee(null);
                }}
                onConfirm={handleCancelConfirm}
                isLoading={isCancelSubmitting}
            />

            {/* Update Registration Dialog */}
            <EventActionDialog
                open={updateDialogOpen}
                actionType="update"
                userName={selectedAttendee?.profile?.name || ''}
                eventTitle={selectedEvent?.title || ''}
                onClose={() => {
                    setUpdateDialogOpen(false);
                    setSelectedAttendee(null);
                }}
                onConfirm={handleUpdateConfirm}
                isFoodEnabled={!!selectedEvent?.food}
                isAccompanyEnabled={selectedEvent?.isAccompanyEnabled || false}
                foodOptions={foodOptions}
                initialFoodPreference={selectedAttendee?.foodPreference || ''}
                initialCount={selectedAttendee?.headCount ?? 1}
                isLoading={isUpdateSubmitting}
            />

            {/* Info Dialog */}
            <Dialog
                open={infoDialogState.open}
                onClose={handleInfoDialogClose}
                maxWidth="sm"
                fullWidth
            >
                <DialogTitle sx={{ pb: 1 }}>
                    Attendee Details
                </DialogTitle>
                <DialogContent>
                    {infoDialogState.attendee && (
                        <Box sx={{ pt: 0.5 }}>
                            <Typography variant="body1" gutterBottom sx={{ mb: 2, fontWeight: 500 }}>
                                {infoDialogState.attendee.profile?.name}
                            </Typography>
                            <Divider sx={{ my: 2 }} />
                            
                            {/* Batch */}
                            <Box sx={{ mb: 2, display: 'flex', alignItems: 'center', gap: 1 }}>
                                <SchoolIcon color="primary" />
                                <Box>
                                    <Typography variant="body2" color="text.secondary">
                                        Batch
                                    </Typography>
                                    <Typography variant="body1" sx={{ fontWeight: 500 }}>
                                        {infoDialogState.attendee.profile?.batch}
                                    </Typography>
                                </Box>
                            </Box>

                            {/* School */}
                            <Box sx={{ mb: 2, display: 'flex', alignItems: 'center', gap: 1 }}>
                                <SchoolIcon color="primary" />
                                <Box>
                                    <Typography variant="body2" color="text.secondary">
                                        School
                                    </Typography>
                                    <Typography variant="body1" sx={{ fontWeight: 500 }}>
                                        {infoDialogState.attendee.profile?.firstJnvName || 'N/A'}
                                    </Typography>
                                </Box>
                            </Box>

                            {/* Food Preference */}
                            <Box sx={{ mb: 2, display: 'flex', alignItems: 'center', gap: 1 }}>
                                <RestaurantIcon color="primary" />
                                <Box>
                                    <Typography variant="body2" color="text.secondary">
                                        Food Preference
                                    </Typography>
                                    <Typography variant="body1" sx={{ fontWeight: 500 }}>
                                        {infoDialogState.attendee.foodPreference && infoDialogState.attendee.foodPreference.trim() !== '' 
                                            ? infoDialogState.attendee.foodPreference 
                                            : 'Null'}
                                    </Typography>
                                </Box>
                            </Box>

                            {/* Head Count */}
                            <Box sx={{ mb: 2, display: 'flex', alignItems: 'center', gap: 1 }}>
                                <GroupIcon color="primary" />
                                <Box>
                                    <Typography variant="body2" color="text.secondary">
                                        Head Count
                                    </Typography>
                                    <Typography variant="body1" sx={{ fontWeight: 500 }}>
                                        {infoDialogState.attendee.headCount ?? 1} {(infoDialogState.attendee.headCount ?? 1) === 1 ? 'person' : 'people'}
                                    </Typography>
                                </Box>
                            </Box>

                            {/* Donation Amount */}
                            <Box sx={{ mb: 2, display: 'flex', alignItems: 'center', gap: 1 }}>
                                <CurrencyRupeeIcon sx={{ color: 'secondary.main' }} />
                                <Box sx={{ width: '100%' }}>
                                    <Typography variant="body2" color="text.secondary">
                                        Donation Details
                                    </Typography>
                                    {infoDialogState.attendee.donation ? (
                                        <>
                                            {infoDialogState.attendee.donation.split(',').map((donation, index) => {
                                                const [amount, ref] = donation.trim().split('@');
                                                return (
                                                    <Typography 
                                                        key={index} 
                                                        variant="body2" 
                                                        sx={{ 
                                                            fontFamily: 'monospace',
                                                            fontSize: '0.875rem',
                                                            mt: 0.5
                                                        }}
                                                    >
                                                        ₹{amount} (Ref: {ref})
                                                    </Typography>
                                                );
                                            })}
                                            <Typography 
                                                variant="body1" 
                                                sx={{ 
                                                    color: 'secondary.main',
                                                    mt: 1
                                                }}
                                            >
                                                Total: ₹{infoDonationTotal}
                                            </Typography>
                                        </>
                                    ) : (
                                        <Typography 
                                            variant="body1" 
                                            sx={{ 
                                                fontWeight: 500,
                                                color: 'text.secondary'
                                            }}
                                        >
                                            ₹0
                                        </Typography>
                                    )}
                                </Box>
                            </Box>

                            {/* Phone */}
                            <Box sx={{ mb: 2, display: 'flex', alignItems: 'center', gap: 1 }}>
                                <PhoneIcon color="primary" />
                                <Box>
                                    <Typography variant="body2" color="text.secondary">
                                        Phone
                                    </Typography>
                                    <Typography variant="body1" sx={{ fontWeight: 500 }}>
                                        {infoDialogState.attendee.profile?.phone}
                                    </Typography>
                                </Box>
                            </Box>

                            {/* Check-in Status */}
                            <Box sx={{ mb: 2, display: 'flex', alignItems: 'center', gap: 1 }}>
                                {(infoDialogState.attendee?.checkedInAt ?? 0) > 0 ? (
                                    <CheckCircleIcon color="success" />
                                ) : (
                                    <CancelIcon color="disabled" />
                                )}
                                <Box>
                                    <Typography variant="body2" color="text.secondary">
                                        Check-in Status
                                    </Typography>
                                    <Typography 
                                        variant="body1" 
                                        sx={{ 
                                            fontWeight: 500,
                                            color: (infoDialogState.attendee.checkedInAt ?? 0) > 0 ? 'success.main' : 'text.secondary'
                                        }}
                                    >
                                        {(infoDialogState.attendee.checkedInAt ?? 0) > 0 
                                            ? `Checked in - ${UnixDateTimeToReadable(infoDialogState.attendee.checkedInAt ?? 0)}`
                                            : 'Not checked in'}
                                    </Typography>
                                </Box>
                            </Box>

                            {/* Registration Time */}
                            <Box sx={{ mb: 2, display: 'flex', alignItems: 'center', gap: 1 }}>
                                <EventAvailableIcon color="info" />
                                <Box>
                                    <Typography variant="body2" color="text.secondary">
                                        Registration Time
                                    </Typography>
                                    <Typography variant="body1" sx={{ fontWeight: 500 }}>
                                        {infoDialogState.attendee.createdAt 
                                            ? UnixDateTimeToReadable(infoDialogState.attendee.createdAt)
                                            : 'Not available'}
                                    </Typography>
                                </Box>
                            </Box>
                        </Box>
                    )}
                </DialogContent>
                <DialogActions>
                    <Button onClick={handleInfoDialogClose} color="primary" variant="contained">
                        Close
                    </Button>
                </DialogActions>
            </Dialog>

            {/* Donation Dialog */}
            <Dialog 
                open={donationDialogOpen} 
                onClose={() => setDonationDialogOpen(false)}
                maxWidth="xs"
                fullWidth
            >
                <DialogTitle>
                    Add Donation
                    {selectedAttendee && (
                        <Typography variant="body2" color="text.secondary">
                            {selectedAttendee.profile?.name} ({selectedAttendee.profile?.batch})
                        </Typography>
                    )}
                </DialogTitle>
                <DialogContent>
                    {selectedAttendee && selectedAttendee.donation && (
                        <Box sx={{ mb: 3, p: 2, backgroundColor: 'action.hover', borderRadius: 1 }}>
                            <Typography variant="body2" color="text.secondary" sx={{ mb: 1, fontWeight: 600 }}>
                                Previous Donations:
                            </Typography>
                            {selectedAttendee.donation.split(',').map((donation, index) => {
                                const [amount, ref] = donation.trim().split('@');
                                return (
                                    <Typography key={index} variant="body2" sx={{ fontFamily: 'monospace' }}>
                                        ₹{amount} (Ref: {ref})
                                    </Typography>
                                );
                            })}
                            <Typography variant="body2" sx={{ mt: 1, color: 'secondary.main' }}>
                                Total: ₹{selectedAttendeeDonationTotal}
                            </Typography>
                        </Box>
                    )}

                    {/* Donation Entry - Separate Amount and Transaction Ref Fields */}
                    <Box sx={{ mb: 2 }}>
                        <TextField
                            label="Amount (₹)"
                            type="text"
                            variant="outlined"
                            size="small"
                            value={donationAmount}
                            onChange={handleDonationAmountChange}
                            placeholder="200"
                            sx={{ mb: 2, width: '100%', mt: 1 }}
                            slotProps={{ htmlInput: { inputMode: 'numeric', pattern: '[0-9]*' } }}
                            autoFocus
                        />
                        <TextField
                            label="Transaction Reference"
                            type="text"
                            variant="outlined"
                            size="small"
                            value={donationTxnRef}
                            onChange={handleDonationTxnRefChange}
                            placeholder="ABC123"
                            sx={{ width: '100%' }}
                        />
                    </Box>
                </DialogContent>
                <DialogActions>
                    <Button 
                        onClick={() => {
                            if (!isDonationSubmitting) {
                                setDonationDialogOpen(false);
                            }
                        }} 
                        color="inherit"
                        disabled={isDonationSubmitting}
                    >
                        Cancel
                    </Button>
                    <Button 
                        onClick={handleDonationConfirm} 
                        color="primary" 
                        variant="contained"
                        disabled={isDonationSubmitting}
                    >
                        {isDonationSubmitting ? 'Submitting...' : 'Submit'}
                    </Button>
                </DialogActions>
            </Dialog>
        </Box>
    );
};
