import React from 'react';
import { Box, IconButton, TableCell, TableRow, Tooltip, Typography } from '@mui/material';
import { Link } from '@tanstack/react-router';
import CheckCircleIcon from '@mui/icons-material/CheckCircle';
import CancelIcon from '@mui/icons-material/Cancel';
import PhoneIcon from '@mui/icons-material/Phone';
import WhatsAppIcon from '@mui/icons-material/WhatsApp';
import InfoIcon from '@mui/icons-material/Info';
import RestaurantIcon from '@mui/icons-material/Restaurant';
import CurrencyRupeeIcon from '@mui/icons-material/CurrencyRupee';
import EditIcon from '@mui/icons-material/Edit';
import { AttendeeBasicInfo } from '@/types/attendee.types';
import { calculateDonationTotal } from '@/utils/eventCalculations';
import { UnixDateTimeToReadable } from '@/utils/common';

// Helper – kept here to avoid being recreated on each parent render
const formatPhoneNumber = (phone: string): string => {
    if (!phone) return '';
    const cleaned = phone.replace(/\D/g, '');
    if (cleaned.length === 10) return `91${cleaned}`;
    if (cleaned.startsWith('91') && cleaned.length === 12) return cleaned;
    return cleaned;
};

export interface AttendeeRowProps {
    attendee: AttendeeBasicInfo;
    isCheckinEnabled: boolean;
    getFoodColor: (foodPref: string) => { bg: string; text: string };
    onInfo: (attendee: AttendeeBasicInfo) => void;
    onDonation: (attendee: AttendeeBasicInfo) => void;
    onCancel: (attendee: AttendeeBasicInfo) => void;
    onCheckIn: (attendee: AttendeeBasicInfo) => void;
    onUpdate: (attendee: AttendeeBasicInfo) => void;
}

const AttendeeRowImpl: React.FC<AttendeeRowProps> = ({
    attendee,
    isCheckinEnabled,
    getFoodColor,
    onInfo,
    onDonation,
    onCancel,
    onCheckIn,
    onUpdate,
}) => {
    const checkedIn = (attendee.checkedInAt ?? 0) > 0;
    const headCount = attendee.headCount ?? 1;
    const phone = attendee.profile?.phone ?? '';

    return (
        <TableRow
            hover
            sx={{
                backgroundColor: checkedIn ? 'rgba(76, 175, 80, 0.08)' : 'inherit',
                '&:hover': {
                    backgroundColor: checkedIn ? 'rgba(76, 175, 80, 0.15)' : undefined,
                },
            }}
        >
            <TableCell sx={{ py: { xs: 0.5, sm: 1.5 }, px: { xs: 0.5, sm: 1 } }}>
                {/* Line 1: Name + info */}
                <Box sx={{ mb: 0.2, display: 'flex', alignItems: 'center', gap: 0.5 }}>
                    <Link
                        to={`/profile/${attendee.userId}` as string}
                        style={{
                            textDecoration: 'none',
                            color: 'inherit',
                            fontWeight: 500,
                            fontSize: '0.9rem',
                        }}
                    >
                        {attendee.profile?.name}
                    </Link>
                    <Tooltip title="View Details">
                        <IconButton
                            size="small"
                            onClick={() => onInfo(attendee)}
                            sx={{ ml: 0.5, padding: '2px' }}
                        >
                            <InfoIcon sx={{ fontSize: '0.9rem', color: 'info.main' }} />
                        </IconButton>
                    </Tooltip>
                </Box>

                {/* Line 2: Phone | check-in icon | x1 | batch */}
                <Box sx={{ fontSize: '0.85rem', color: 'text.disabled', display: 'flex', alignItems: 'center', gap: 0.5 }}>
                    <Box sx={{ display: 'flex', gap: 0.8 }}>
                        <Tooltip title="Call">
                            <IconButton size="small" href={`tel:${phone}`} sx={{ padding: '1px' }}>
                                <PhoneIcon sx={{ fontSize: '1.05rem', color: 'primary.main' }} />
                            </IconButton>
                        </Tooltip>
                        <Tooltip title="WhatsApp">
                            <IconButton
                                size="small"
                                href={`https://wa.me/${formatPhoneNumber(phone)}`}
                                target="_blank"
                                rel="noopener noreferrer"
                                sx={{ padding: '1px' }}
                            >
                                <WhatsAppIcon sx={{ fontSize: '1.05rem', color: '#25D366' }} />
                            </IconButton>
                        </Tooltip>
                    </Box>

                    <Tooltip title={checkedIn ? `Checked in - ${UnixDateTimeToReadable(attendee.checkedInAt ?? 0)}` : 'Not checked in'}>
                        <CheckCircleIcon
                            sx={{
                                fontSize: '1.05rem',
                                color: checkedIn ? 'success.main' : 'text.disabled',
                            }}
                        />
                    </Tooltip>

                    {attendee.donation && attendee.donation.trim() !== '' && (
                        <Tooltip title={`Donated: ₹${calculateDonationTotal(attendee.donation)}`}>
                            <CurrencyRupeeIcon sx={{ fontSize: '1.05rem', color: 'success.main' }} />
                        </Tooltip>
                    )}

                    {attendee.foodPreference && attendee.foodPreference.trim() !== '' && (
                        <Tooltip title={`Food: ${attendee.foodPreference}`}>
                            <RestaurantIcon
                                sx={{
                                    fontSize: '1.05rem',
                                    color: getFoodColor(attendee.foodPreference).text,
                                }}
                            />
                        </Tooltip>
                    )}

                    <Typography
                        component="span"
                        variant="body2"
                        sx={{
                            px: 0.6,
                            py: 0.1,
                            backgroundColor: headCount > 1 ? 'primary.main' : 'grey.400',
                            color: 'white',
                            borderRadius: '4px',
                            fontSize: '0.75rem',
                            fontWeight: 600,
                        }}
                    >
                        x{headCount}
                    </Typography>

                    <Typography component="span" variant="body2" sx={{ color: 'text.secondary', fontSize: '0.85rem' }}>
                        ({attendee.profile?.batch})
                    </Typography>
                </Box>
            </TableCell>

            {/* Action buttons */}
            <TableCell align="right" sx={{ py: { xs: 0.5, sm: 1.5 }, pl: 0, pr: { xs: 0.25, sm: 1 } }}>
                <Box sx={{ display: 'flex', gap: 0.3, justifyContent: 'flex-end' }}>
                    <Tooltip title="Add Donation">
                        <IconButton
                            onClick={() => onDonation(attendee)}
                            sx={{ color: 'secondary.main', padding: { xs: '4px', sm: '8px' } }}
                        >
                            <CurrencyRupeeIcon sx={{ fontSize: { xs: '20px', sm: '24px' } }} />
                        </IconButton>
                    </Tooltip>

                    <Tooltip title={(attendee.headCount ?? 0) === 0 ? 'Headcount already zero' : 'Cancel Registration'}>
                        <span>
                            <IconButton
                                color="error"
                                onClick={() => onCancel(attendee)}
                                disabled={(attendee.headCount ?? 0) === 0}
                                sx={{ padding: { xs: '4px', sm: '8px' } }}
                            >
                                <CancelIcon sx={{ fontSize: { xs: '20px', sm: '24px' } }} />
                            </IconButton>
                        </span>
                    </Tooltip>

                    {isCheckinEnabled ? (
                        <Tooltip title={checkedIn ? 'Already Checked In' : 'Check-in'}>
                            <span>
                                <IconButton
                                    color={checkedIn ? 'default' : 'success'}
                                    onClick={() => onCheckIn(attendee)}
                                    disabled={checkedIn}
                                    sx={{ padding: { xs: '4px', sm: '8px' } }}
                                >
                                    <CheckCircleIcon sx={{ fontSize: { xs: '20px', sm: '24px' } }} />
                                </IconButton>
                            </span>
                        </Tooltip>
                    ) : (
                        <Tooltip title="Update Registration">
                            <IconButton
                                color="primary"
                                onClick={() => onUpdate(attendee)}
                                sx={{ padding: { xs: '4px', sm: '8px' } }}
                            >
                                <EditIcon sx={{ fontSize: { xs: '20px', sm: '24px' } }} />
                            </IconButton>
                        </Tooltip>
                    )}
                </Box>
            </TableCell>
        </TableRow>
    );
};

// Custom equality: re-render the row only when *its* attendee object or relevant flags change.
// All callbacks are required to be stable (useCallback with no changing deps) by the parent.
export const AttendeeRow = React.memo(AttendeeRowImpl, (prev, next) => {
    return (
        prev.attendee === next.attendee &&
        prev.isCheckinEnabled === next.isCheckinEnabled &&
        prev.getFoodColor === next.getFoodColor &&
        prev.onInfo === next.onInfo &&
        prev.onDonation === next.onDonation &&
        prev.onCancel === next.onCancel &&
        prev.onCheckIn === next.onCheckIn &&
        prev.onUpdate === next.onUpdate
    );
});
